### Шаг 3: Создание тестов в `tests/test_notes.py`

Создайте директорию `tests` и внутри нее файл `test_notes.py` с следующим содержимым:

```python
import json
import os
import tempfile
from unittest import TestCase

from notes import load_notes, save_notes, add_note, list_notes, search_notes, delete_note

class TestNotes(TestCase):
    def setUp(self):
        self.temp_storage = tempfile.NamedTemporaryFile(delete=False)
        os.environ['STORAGE_FILE'] = self.temp_storage.name

    def tearDown(self):
        os.unlink(self.temp_storage.name)

    def test_add_note(self):
        add_note("Test note")
        notes = load_notes()
        self.assertEqual(notes, ["Test note"])

    def test_list_notes(self):
        add_note("First note")
        add_note("Second note")
        self.assertEqual(list_notes(), None)
        notes = load_notes()
        self.assertEqual(len(notes), 2)

    def test_search_notes(self):
        add_note("Apple")
        add_note("Banana")
        add_note("Cherry")
        search_notes("ap")
        notes = load_notes()
        self.assertIn("Apple", notes)

    def test_delete_note(self):
        add_note("First note")
        add_note("Second note")
        delete_note(1)
        notes = load_notes()
        self.assertEqual(notes, ["Second note"])

if __name__ == "__main__":
    import unittest
    unittest.main(argv=[''], exit=False)
```

### Шаг 4: Запуск тестов

Для запуска тестов используйте следующую команду:

```sh
python -m pytest tests/test_notes.py
```

Это должно запустить все тесты и вывести результаты. Если все тесты проходят успешно, значит, ваш проект готов к использованию.

